10	/**
11	 * Factory for creating pre-configured event system instances.
12	 */
13	export function createEventSystem(config?: Partial<EventConfig>): SystemComponents {
14	  const bus = new EventBus(config);
15	  const store = new EventStore(bus);
16	  const router = new EventRouter(bus);
17	  return { bus, store, router };
