27	/**
28	 * Create a pair of buses with a router connecting them.
29	 */
30	export function createLinkedBuses(config?: Partial<EventConfig>): { primary: EventBus; secondary: EventBus; router: EventRouter } {
31	  const primary = new EventBus(config);
32	  const secondary = new EventBus(config);
33	  const router = new EventRouter(primary);
34	  router.addRule('.*', secondary);
35	  return { primary, secondary, router };
